section.programlisting:
cassandra().poll {
    connect {
        servers = listOf("localhost:9042")
        keyspace = "iot"
        datacenterName = "datacenter1"
    }
    query("SELECT deviceid, timestamp, batterylevel FROM devices WHERE company = ? ORDER BY timestamp")
    parameters("ACME Inc.")
    tieBreaker {
        name = "timestamp"
        type = GenericType.INSTANT
    }
    pollDelay(Duration.ofSeconds(1))
}

.cassandra()
.save {
    connect {
        servers = listOf("localhost:9042")
        keyspace = "iot"
        datacenterName = "datacenter1"
    }

    table { _, _ ->
        "batteryState"
    }

    columns { _, _ ->
        listOf(
            "company",
            "deviceid",
            "timestamp,
            "batterylevel"
        )
    }

    rows { _, input ->
        listOf(
            CassandraSaveRow(
                "'ACME Inc.'",
                "'${input.deviceId}'",
                "'${input.timestamp}'",
                input.batteryLevel
            )
        )
    }
}

 cassandra().search {
    name = "search"

    connect {
        servers = listOf("localhost:9042")
        keyspace = "test_keyspace"
        datacenterName = "test_datacenter"
    }
    query { _, _ ->
        "SELECT * FROM "batteryState" WHERE  "company"= ? AND "deviceid"" = ? AND timestamp = ?"
    }
    parameters { _, input ->
        listOf("ACME Inc.", input.input.deviceId, input.input.timestamp)
    }
}

elasticsearch().poll {
    name = "poll"
    client { RestClient.builder(HttpHost.create("http://localhost:9200")).build() }
    query {
        """{
            "query":{
                "match_all":{}
            },
            "sort" : ["_score"]
        }""".trimIndent()
    }
    index("battery-state")
    pollDelay(Duration.ofSeconds(1))
}

.elasticsearch()
.save {
    name = "save"
    client {
        RestClient.builder(HttpHost.create("http://localhost:9200")).build()
    }
    documents { _, input ->
        listOf(
            Document(
                index = "battery-state",
                id = input.primaryKey,
                source = objectMapper.writeValueAsString(input)
            )
        )
    }
}

.elasticsearch()
.search {
    name = "search"
    client {
        RestClient.builder(HttpHost.create("http://localhost:9200")).build()
    }
    index { _, _ -> listOf("battery-state") }
    query { _, input ->
        """{
            "query": {
                "bool": {
                    "must": [
                        { "match": { "deviceId": "${input.input.deviceId}" }},
                        { "term": { "timestamp": ${input.input.timestamp.epochSecond} }}
                    ]
                }
            }
        }"""
    }
}

listitem.programlisting:
influxdb().poll {
    connect {
        server(
            url = "http://localhost:18086",
            bucket = "iot",
            org = "qalipsis"
        )
        basic(user = "DomFisher", password = "Calgary1987")
    }
    query(
        """
        from(bucket:"${iot}")
            |> range(start: -15m)
            |> filter(
                fn: (r) => r._measurement == "battery_state"
                )
    """.trimIndent()
    )
    pollDelay(Duration.ofSeconds(1))
}

.save {
    connect {
        server(
            url =  "http://localhost:18086",
            bucket = "iot",
            org = "qalipsis"
        )
        basic(user = "DomFisher", password = "Calgary1987")
    }
    query {
        bucket = { _, _ -> "iot" }
        organization = { _, _ -> "qalipsis" }
        points = { _, input ->
            listOf(
                Point.measurement("battery_state")
                    .addField("battery_level", input.batteryLevel)
                    .addTag("device_id", input.deviceId)
                    .addTag("timestamp", input.timestamp.epochSecond.toString())
            )
        }
    }
}

section.programlisting:
.influxdb()
.search {
    connect {
        server(
            url = "http://localhost:18086",
            bucket = "iot",
            org = "qalipsis"
        )
        basic(user = "DomFisher", password = "Calgary1987")
    }
    query { _, input ->
        """
            from(bucket: "${iot}")
                    |> range(start: -15m)
                    |> filter(
                        fn: (r) => r._measurement == "${"battery_state"}" and
                            r.${"device_id"} == "${input.deviceId}" and
                            r.${"timestamp"} == "${input.timestamp.epochSecond}"
                        )
        """.trimIndent()
    }
}

